server.tool(
  'CekSenet_NotEklePost',
  '[Kategori\/Controller: CekSenet]\n\nÇek ve Senet kayıtlarının (kıymetli evrak portföyü) yönetimi için Web API controller\'ı.\r\n             Müşteriden alınan (Müşteri Çeki\/Senedi) veya satıcıya verilen (Kendi Çekimiz\/Senedimiz) evrakların \r\n             tüm yaşam döngüsünü, CRUD işlemlerini ve portföy takibini yönetir.\r\n            \r\n             ENTITY: CekSenet\r\n             ALT_ADLAR: Çek, Senet, Kıymetli Evrak, Müşteri Çeki, Borç Senedi, PromissoryNote, CheckManagement, BillOfExchange\r\n             ROUTE: \/api\/CekSenet\r\n            \r\n             ZORUNLU_ALANLAR:\r\n               Vade      — Evrakın ödeme tarihi (vadesi).\r\n               Tutar     — Evrakın nominal tutarı.\r\n               SeriNo    — Evrak üzerindeki seri\/numara bilgisi.\r\n               TipID     — Alınan veya Verilen çek\/senet ayrımı.\r\n            \r\n             IS_KURALLARI:\r\n               - Evrak numarası (SeriNo) portföy içinde benzersiz olmalıdır.\r\n               - Üzerinde finansal hareket (Ciro, Tahsilat, İade, Protesto vb.) oluşmuş evraklar silinemez; yalnızca durumları güncellenebilir.\r\n               - Vadesi geçmiş evraklar için sistem otomatik risk uyarısı veya gecikme raporu üretebilir.\r\n            \r\n             ILISKILI_MODULLER:\r\n               - Cari : Evrakın alındığı veya ciro edildiği iş ortağı.\r\n               - Banka : Çekin keşide edildiği veya takasa verildiği banka şubesi.\r\n               - Hareket : Evrakın yaşam döngüsü boyunca geçirdiği aşamalar (Ciro, Tahsil edildi vb.).\r\n               - Kasa\/Banka : Evrak tahsil edildiğinde paranın aktarıldığı hesaplar.\r\n            \r\n             MCP_CATEGORY: FinansYonetimi\r\n             MCP_ONCELIK: Portföy analizi ve vadesi yaklaşan evrakları listelemek için ListeGet kullanılır.\r\n                          Yeni evrak girişi (Tahsilat\/Ödeme esnasında) için standart Post kullanılır.\n\n[Endpoint İşlevi]:\n(endpoint aciklamasi yok)',
  {
    pathParams: CekSenetNotEklePostParams,
    bodyParams: CekSenetNotEklePostBody
  },
  CekSenet_NotEklePostHandler
);

