server.tool(
  'HareketTurleriAlt_GetGet',
  '[Kategori\/Controller: HareketTurleriAlt]\n\nERP sistemindeki hareket türlerinin alt kırılımlarını (alt türlerini) yöneten Web API controller\'ı.\r\n             Stok, cari veya finans hareketlerinde (Fatura, Fiş, Havale vb.) çok daha detaylı gruplama, analiz ve özel raporlama boyutları oluşturmak için kullanılır.\r\n            \r\n             ENTITY: HareketTurleriAlt\r\n             ALT_ADLAR: Alt Hareket Türü, Hareket Alt Kırılımı, İşlem Alt Kategorisi, Özelleştirilmiş İşlem Türü, TransactionSubType, MovementSubCategory, SubType\r\n             ROUTE: \/api\/HareketTurleriAlt\r\n            \r\n             ZORUNLU_ALANLAR:\r\n               HareketTurID — Alt türün bağlı olduğu ana hareket türü (örn: Stok Giriş, Cari Tahsilat).\r\n               AltHarTurKodu — Alt türün benzersiz referans kodu.\r\n               AltHarTurAdi  — Alt türün açıklayıcı ismi.\r\n            \r\n             IS_KURALARI:\r\n               - Her alt tür mutlaka geçerli bir ana hareket türüne (HareketTurID) bağlı olmalıdır.\r\n               - Herhangi bir operasyonel hareket (fatura satırı, kasa fişi, banka hareketi vb.) tarafından referans gösterilen alt türler silinemez; yalnızca pasifleştirilebilir.\r\n               - Alt türler, raporlarda \"Gider Türü\", \"Gelir Sebebi\" gibi kırılımları detaylandırmak için kullanılır.\r\n            \r\n             ILISKILI_MODULLER:\r\n               - HareketTurleri : Alt türlerin bağlı olduğu ana işlem kategorileri.\r\n               - Stok \/ Cari \/ Banka \/ Kasa : Hareket anında bu alt türlerin seçildiği ana modüller.\r\n               - Raporlar : Operasyonel verilerin bu alt kırılım boyutunda analiz edilmesi.\r\n            \r\n             MCP_CATEGORY: SistemYonetimi\r\n             MCP_ONCELIK: Bir ana hareket türüne (örn: Satış Faturaları) ait alt kırılımları listelemek için HareketTurID filtresiyle ListeGet kullanılır.\r\n                          Açıklayıcı bir alt kategori eklemek için standart Post tercih edilir.\n\n[Endpoint İşlevi]:\nBelirtilen ID\'ye sahip kaydı getirir. Kart detay bilgilerini döndürür.\r\nINTENT: kaydı getir, detayı göster, bilgileri al, ID ile sorgula, kartı görüntüle\r\nKULLANIM: Kart görüntüleme, düzenleme öncesi mevcut bilgileri alma.',
  {
    pathParams: HareketTurleriAltGetGetParams
  },
  HareketTurleriAlt_GetGetHandler
);

server.tool(
  'HareketTurleriAlt_PutPut',
  '[Kategori\/Controller: HareketTurleriAlt]\n\nERP sistemindeki hareket türlerinin alt kırılımlarını (alt türlerini) yöneten Web API controller\'ı.\r\n             Stok, cari veya finans hareketlerinde (Fatura, Fiş, Havale vb.) çok daha detaylı gruplama, analiz ve özel raporlama boyutları oluşturmak için kullanılır.\r\n            \r\n             ENTITY: HareketTurleriAlt\r\n             ALT_ADLAR: Alt Hareket Türü, Hareket Alt Kırılımı, İşlem Alt Kategorisi, Özelleştirilmiş İşlem Türü, TransactionSubType, MovementSubCategory, SubType\r\n             ROUTE: \/api\/HareketTurleriAlt\r\n            \r\n             ZORUNLU_ALANLAR:\r\n               HareketTurID — Alt türün bağlı olduğu ana hareket türü (örn: Stok Giriş, Cari Tahsilat).\r\n               AltHarTurKodu — Alt türün benzersiz referans kodu.\r\n               AltHarTurAdi  — Alt türün açıklayıcı ismi.\r\n            \r\n             IS_KURALARI:\r\n               - Her alt tür mutlaka geçerli bir ana hareket türüne (HareketTurID) bağlı olmalıdır.\r\n               - Herhangi bir operasyonel hareket (fatura satırı, kasa fişi, banka hareketi vb.) tarafından referans gösterilen alt türler silinemez; yalnızca pasifleştirilebilir.\r\n               - Alt türler, raporlarda \"Gider Türü\", \"Gelir Sebebi\" gibi kırılımları detaylandırmak için kullanılır.\r\n            \r\n             ILISKILI_MODULLER:\r\n               - HareketTurleri : Alt türlerin bağlı olduğu ana işlem kategorileri.\r\n               - Stok \/ Cari \/ Banka \/ Kasa : Hareket anında bu alt türlerin seçildiği ana modüller.\r\n               - Raporlar : Operasyonel verilerin bu alt kırılım boyutunda analiz edilmesi.\r\n            \r\n             MCP_CATEGORY: SistemYonetimi\r\n             MCP_ONCELIK: Bir ana hareket türüne (örn: Satış Faturaları) ait alt kırılımları listelemek için HareketTurID filtresiyle ListeGet kullanılır.\r\n                          Açıklayıcı bir alt kategori eklemek için standart Post tercih edilir.\n\n[Endpoint İşlevi]:\n(endpoint aciklamasi yok)',
  {
    pathParams: HareketTurleriAltPutPutParams,
    bodyParams: HareketTurleriAltPutPutBody
  },
  HareketTurleriAlt_PutPutHandler
);

