server.tool(
  'Paket_DeleteDelete',
  '[Kategori\/Controller: Paket]\n\nStokların paket bazlı takibi, raf\/palet yönetimi ve lojistik sevkiyat süreçleri için kullanılan benzersiz (unique) paket birimlerinin yönetimi için Web API controller\'ı.\r\n             Farklı stok kalemlerinin ve miktarlarının içinde bulunduğu koli, palet veya konteyner tipi yapıların tekilleştirilerek izlenmesini ve hacimsel takibini sağlar.\r\n            \r\n             ENTITY: Paket\r\n             ALT_ADLAR: Koli, Palet, Taşıma Birimi, Paketleme Türü, Kap Cinsi, UniquePackage, HandlingUnit, LogisticsUnit, Package, Case, Palette, SSCC\r\n             ROUTE: \/api\/Paket\r\n            \r\n             ZORUNLU_ALANLAR:\r\n               PaketKodu — Paketin benzersiz referans veya barkod kodu (zorunlu).\r\n               PaketAdi  — Paketin açıklayıcı ismi (örn: Standart Euro Palet).\r\n            \r\n             IS_KURALLARI:\r\n               - Paket kodları sistem genelinde benzersiz olmalıdır; lojistik standartlara (SSCC vb.) uygun barkod üretimi yapılabilir.\r\n               - İçinde stok hareketi barındıran, raf ataması yapılmış veya sevkiyat sürecine dahil edilmiş paket tanımları silinemez.\r\n               - Paketler; boyut (en, boy, yükseklik), ağırlık kapasitesi ve kap cinsi (karton koli, plastik kasa vb.) gibi teknik parametrelerle yönetilir.\r\n            \r\n             ILISKILI_MODULLER:\r\n               - Stok : Paketin içindeki ürün kalemleri ve miktarları.\r\n               - Depo \/ Raf : Paketlerin fiziksel olarak bulunduğu konumların takibi.\r\n               - Irsaliye \/ Sevkiyat : Paket bazlı (okutarak) yükleme ve sevkiyat operasyonları.\r\n               - E-Irsaliye : Paketleme bilgilerinin dijital dökümanlara ve taşıyıcı sistemlerine aktarımı.\r\n            \r\n             MCP_CATEGORY: StokYonetimi\r\n             MCP_ONCELIK: Depo personeli tarafından paket içeriğini sorgulamak veya yeni bir sevkiyat paketi oluşturmak için kullanılır.\r\n                          Aktif paket listelerini almak için ListeGet; lojistik parametre güncellemeleri için Put tercih edilir.\n\n[Endpoint İşlevi]:\nBelirtilen kaydı siler veya pasifleştirir.\r\nINTENT: sil, kaldır, pasifleştir, devre dışı bırak, kapat\r\nKULLANIM: Artık kullanılmayan kayıtları sistemden kaldırma veya pasifleştirme.\r\nIS_KURALLARI: Hareketi veya bağlı kaydı bulunan kartlar tamamen silinemez; yalnızca pasifleştirilebilir.',
  {
    pathParams: PaketDeleteDeleteParams
  },
  Paket_DeleteDeleteHandler
);

server.tool(
  'Paket_ListeGetGet',
  '[Kategori\/Controller: Paket]\n\nStokların paket bazlı takibi, raf\/palet yönetimi ve lojistik sevkiyat süreçleri için kullanılan benzersiz (unique) paket birimlerinin yönetimi için Web API controller\'ı.\r\n             Farklı stok kalemlerinin ve miktarlarının içinde bulunduğu koli, palet veya konteyner tipi yapıların tekilleştirilerek izlenmesini ve hacimsel takibini sağlar.\r\n            \r\n             ENTITY: Paket\r\n             ALT_ADLAR: Koli, Palet, Taşıma Birimi, Paketleme Türü, Kap Cinsi, UniquePackage, HandlingUnit, LogisticsUnit, Package, Case, Palette, SSCC\r\n             ROUTE: \/api\/Paket\r\n            \r\n             ZORUNLU_ALANLAR:\r\n               PaketKodu — Paketin benzersiz referans veya barkod kodu (zorunlu).\r\n               PaketAdi  — Paketin açıklayıcı ismi (örn: Standart Euro Palet).\r\n            \r\n             IS_KURALLARI:\r\n               - Paket kodları sistem genelinde benzersiz olmalıdır; lojistik standartlara (SSCC vb.) uygun barkod üretimi yapılabilir.\r\n               - İçinde stok hareketi barındıran, raf ataması yapılmış veya sevkiyat sürecine dahil edilmiş paket tanımları silinemez.\r\n               - Paketler; boyut (en, boy, yükseklik), ağırlık kapasitesi ve kap cinsi (karton koli, plastik kasa vb.) gibi teknik parametrelerle yönetilir.\r\n            \r\n             ILISKILI_MODULLER:\r\n               - Stok : Paketin içindeki ürün kalemleri ve miktarları.\r\n               - Depo \/ Raf : Paketlerin fiziksel olarak bulunduğu konumların takibi.\r\n               - Irsaliye \/ Sevkiyat : Paket bazlı (okutarak) yükleme ve sevkiyat operasyonları.\r\n               - E-Irsaliye : Paketleme bilgilerinin dijital dökümanlara ve taşıyıcı sistemlerine aktarımı.\r\n            \r\n             MCP_CATEGORY: StokYonetimi\r\n             MCP_ONCELIK: Depo personeli tarafından paket içeriğini sorgulamak veya yeni bir sevkiyat paketi oluşturmak için kullanılır.\r\n                          Aktif paket listelerini almak için ListeGet; lojistik parametre güncellemeleri için Put tercih edilir.\n\n[Endpoint İşlevi]:\n(endpoint aciklamasi yok)',
  {
    queryParams: PaketListeGetGetQueryParams
  },
  Paket_ListeGetGetHandler
);

