server.tool(
  'Plasiyer_GetGet',
  '[Kategori\/Controller: Plasiyer]\n\nERP satış sistemindeki Plasiyer (Satış Temsilcisi, Saha Elemanı) kayıtlarının yönetimi için Web API controller\'ı.\r\n             Saha satış ekiplerinin tanımlanmasını, bölge sorumlularının atanmasını ve satış temsilcisi bazlı performans takibi için temel verilerin yönetimini sağlar.\r\n            \r\n             ENTITY: Plasiyer\r\n             ALT_ADLAR: Satış Temsilcisi, Saha Elemanı, Bölge Sorumlusu, Rota Elemanı, Prim Sorumlusu, Sales Rep, Sales Representative, Sales Person, Agent, Field Agent, Marketing Representative\r\n             ROUTE: \/api\/Plasiyer\r\n            \r\n             ZORUNLU_ALANLAR:\r\n               PlasiyerKodu — Temsilcinin sistemdeki benzersiz referans kodu (zorunlu).\r\n               PlasiyerAdi  — Temsilcinin tam adı veya ünvanı (zorunlu).\r\n            \r\n             IS_KURALLARI:\r\n               - Plasiyer kodları sistem genelinde benzersiz olmalıdır.\r\n               - Üzerinde finansal (Tahsilat, Prim vb.) veya operasyonel (Fatura, Sipariş, Cari Hareket vb.) kayıt bulunan plasiyerler silinemez; yalnızca \"Pasif\" statüsüne alınabilir.\r\n               - Plasiyerler; belirli cari gruplarına veya coğrafi bölgelere atanarak satış yetki alanları kısıtlanabilir.\r\n            \r\n             ILISKILI_MODULLER:\r\n               - Cari : Müşterilerin sorumlu plasiyer ile eşleştirilmesi.\r\n               - Fatura \/ Siparis : Satış belgelerinde satışı gerçekleştiren temsilcinin takibi.\r\n               - Finans : Plasiyer bazlı tahsilat raporları ve prim hesaplamaları.\r\n               - Rotasyon : Saha ziyaret planları ve rota takibi.\r\n            \r\n             MCP_CATEGORY: SatisYonetimi\r\n             MCP_ONCELIK: Satış ekibini listelemek veya bir cari kartına plasiyer atamak için ListeGet kullanılır.\r\n                          Yeni bir satış temsilcisi işe başladığında Post; bölge veya prim oranı değişikliklerinde Put tercih edilir.\n\n[Endpoint İşlevi]:\nBelirtilen ID\'ye sahip kaydı getirir. Kart detay bilgilerini döndürür.\r\nINTENT: kaydı getir, detayı göster, bilgileri al, ID ile sorgula, kartı görüntüle\r\nKULLANIM: Kart görüntüleme, düzenleme öncesi mevcut bilgileri alma.',
  {
    pathParams: PlasiyerGetGetParams
  },
  Plasiyer_GetGetHandler
);

server.tool(
  'Plasiyer_PutPut',
  '[Kategori\/Controller: Plasiyer]\n\nERP satış sistemindeki Plasiyer (Satış Temsilcisi, Saha Elemanı) kayıtlarının yönetimi için Web API controller\'ı.\r\n             Saha satış ekiplerinin tanımlanmasını, bölge sorumlularının atanmasını ve satış temsilcisi bazlı performans takibi için temel verilerin yönetimini sağlar.\r\n            \r\n             ENTITY: Plasiyer\r\n             ALT_ADLAR: Satış Temsilcisi, Saha Elemanı, Bölge Sorumlusu, Rota Elemanı, Prim Sorumlusu, Sales Rep, Sales Representative, Sales Person, Agent, Field Agent, Marketing Representative\r\n             ROUTE: \/api\/Plasiyer\r\n            \r\n             ZORUNLU_ALANLAR:\r\n               PlasiyerKodu — Temsilcinin sistemdeki benzersiz referans kodu (zorunlu).\r\n               PlasiyerAdi  — Temsilcinin tam adı veya ünvanı (zorunlu).\r\n            \r\n             IS_KURALLARI:\r\n               - Plasiyer kodları sistem genelinde benzersiz olmalıdır.\r\n               - Üzerinde finansal (Tahsilat, Prim vb.) veya operasyonel (Fatura, Sipariş, Cari Hareket vb.) kayıt bulunan plasiyerler silinemez; yalnızca \"Pasif\" statüsüne alınabilir.\r\n               - Plasiyerler; belirli cari gruplarına veya coğrafi bölgelere atanarak satış yetki alanları kısıtlanabilir.\r\n            \r\n             ILISKILI_MODULLER:\r\n               - Cari : Müşterilerin sorumlu plasiyer ile eşleştirilmesi.\r\n               - Fatura \/ Siparis : Satış belgelerinde satışı gerçekleştiren temsilcinin takibi.\r\n               - Finans : Plasiyer bazlı tahsilat raporları ve prim hesaplamaları.\r\n               - Rotasyon : Saha ziyaret planları ve rota takibi.\r\n            \r\n             MCP_CATEGORY: SatisYonetimi\r\n             MCP_ONCELIK: Satış ekibini listelemek veya bir cari kartına plasiyer atamak için ListeGet kullanılır.\r\n                          Yeni bir satış temsilcisi işe başladığında Post; bölge veya prim oranı değişikliklerinde Put tercih edilir.\n\n[Endpoint İşlevi]:\n(endpoint aciklamasi yok)',
  {
    pathParams: PlasiyerPutPutParams,
    bodyParams: PlasiyerPutPutBody
  },
  Plasiyer_PutPutHandler
);

