server.tool(
  'Sirketler_OnayDurumuGet',
  '[Kategori\/Controller: Sirketler]\n\nERP sistemindeki en üst hiyerarşik birim olan Şirket (Legal Entity) kayıtlarının yönetimi için Web API controller\'ı.\r\n             Multi-company (çoklu şirket) yapısındaki tüzel kişiliklerin, vergi kimliklerinin, resmi iletişim bilgilerinin ve global organizasyonel ayarların CRUD işlemlerini sağlar.\r\n            \r\n             ENTITY: Sirketler\r\n             ALT_ADLAR: Firma, Tüzel Kişilik, Kuruluş, Grup Şirketi, Company, Enterprise, LegalEntity, Corporation, Firm, Organization\r\n             ROUTE: \/api\/Sirketler\r\n            \r\n             ZORUNLU_ALANLAR:\r\n               SirketAdi — Şirketin sistemde görünen kısa adı (zorunlu).\r\n               TicaretUnvani — Resmi fatura ve dökümanlarda yer alan tam ünvan.\r\n               VergiNo \/ VergiDairesi — Yasal kimlik ve beyanname süreçleri için.\r\n            \r\n             IS_KURALLARI:\r\n               - Vergi numarası sistem genelinde benzersiz olmalıdır (aynı tüzel kişilik iki kez açılmamalı).\r\n               - Bünyesinde aktif şubesi, personeli veya mali hareketi (Fatura, Yevmiye Fişi, Banka Hareketi vb.) bulunan şirketler sistem bütünlüğü ve yasal izlenebilirlik gereği silinemez.\r\n               - Yeni bir şirket açıldığında, o şirkete özel \"Parametreler\" ve varsayılan \"Muhasebe Hesap Planı\" tanımlanmalıdır.\r\n            \r\n             ILISKILI_MODULLER:\r\n               - Subeler : Şirkete bağlı fiziksel lokasyonlar ve çalışma birimleri.\r\n               - Muhasebe : Şirket bazlı yasal defterlerin ve mizanların tutulması.\r\n               - Personel : Şirket bünyesinde çalışan sigortalı çalışanların özlük takibi.\r\n               - ParametrelerSirketSube : Şirketin çalışma kurallarını belirleyen konfigürasyonlar.\r\n            \r\n             MCP_CATEGORY: SistemYonetimi\r\n             MCP_ONCELIK: Sistemdeki tüm şirketleri listelemek (özellikle giriş\/login aşamasında) veya yeni bir tüzel kişilik tanımlamak için kullanılır.\r\n                          Şirket sicil bilgilerini güncellemek için Put; hiyerarşik listeleme için ListeGet tercih edilir.\n\n[Endpoint İşlevi]:\nBelirtilen kaydın onay durumunu ve onay geçmişini getirir.\r\nINTENT: onay durumu nedir, onaylandı mı, hangi aşamada, onay sorgula\r\nKULLANIM: Onay akışı takibi, kaydın hangi adımda olduğunu öğrenme.',
  {
    pathParams: SirketlerOnayDurumuGetParams
  },
  Sirketler_OnayDurumuGetHandler
);

server.tool(
  'Sirketler_DegisiklikGecmisiGet',
  '[Kategori\/Controller: Sirketler]\n\nERP sistemindeki en üst hiyerarşik birim olan Şirket (Legal Entity) kayıtlarının yönetimi için Web API controller\'ı.\r\n             Multi-company (çoklu şirket) yapısındaki tüzel kişiliklerin, vergi kimliklerinin, resmi iletişim bilgilerinin ve global organizasyonel ayarların CRUD işlemlerini sağlar.\r\n            \r\n             ENTITY: Sirketler\r\n             ALT_ADLAR: Firma, Tüzel Kişilik, Kuruluş, Grup Şirketi, Company, Enterprise, LegalEntity, Corporation, Firm, Organization\r\n             ROUTE: \/api\/Sirketler\r\n            \r\n             ZORUNLU_ALANLAR:\r\n               SirketAdi — Şirketin sistemde görünen kısa adı (zorunlu).\r\n               TicaretUnvani — Resmi fatura ve dökümanlarda yer alan tam ünvan.\r\n               VergiNo \/ VergiDairesi — Yasal kimlik ve beyanname süreçleri için.\r\n            \r\n             IS_KURALLARI:\r\n               - Vergi numarası sistem genelinde benzersiz olmalıdır (aynı tüzel kişilik iki kez açılmamalı).\r\n               - Bünyesinde aktif şubesi, personeli veya mali hareketi (Fatura, Yevmiye Fişi, Banka Hareketi vb.) bulunan şirketler sistem bütünlüğü ve yasal izlenebilirlik gereği silinemez.\r\n               - Yeni bir şirket açıldığında, o şirkete özel \"Parametreler\" ve varsayılan \"Muhasebe Hesap Planı\" tanımlanmalıdır.\r\n            \r\n             ILISKILI_MODULLER:\r\n               - Subeler : Şirkete bağlı fiziksel lokasyonlar ve çalışma birimleri.\r\n               - Muhasebe : Şirket bazlı yasal defterlerin ve mizanların tutulması.\r\n               - Personel : Şirket bünyesinde çalışan sigortalı çalışanların özlük takibi.\r\n               - ParametrelerSirketSube : Şirketin çalışma kurallarını belirleyen konfigürasyonlar.\r\n            \r\n             MCP_CATEGORY: SistemYonetimi\r\n             MCP_ONCELIK: Sistemdeki tüm şirketleri listelemek (özellikle giriş\/login aşamasında) veya yeni bir tüzel kişilik tanımlamak için kullanılır.\r\n                          Şirket sicil bilgilerini güncellemek için Put; hiyerarşik listeleme için ListeGet tercih edilir.\n\n[Endpoint İşlevi]:\nBelirtilen kaydın değişiklik geçmişini getirir. Kim, ne zaman, ne değiştirdi bilgisi.\r\nINTENT: değişiklik geçmişi, kim değiştirdi, ne zaman değişti, log, audit, tarihçe\r\nKULLANIM: Kayıt üzerinde yapılan tüm değişikliklerin izlenmesi ve denetimi.',
  {
    pathParams: SirketlerDegisiklikGecmisiGetParams,
    queryParams: SirketlerDegisiklikGecmisiGetQueryParams
  },
  Sirketler_DegisiklikGecmisiGetHandler
);

