server.tool(
  'StokVergi_GetGet',
  '[Kategori\/Controller: StokVergi]\n\nERP stok sistemindeki ürünlere faturalama ve maliyetleme aşamasında uygulanacak otomatik vergi tanımlarını (KDV, ÖTV, Stopaj, Ek Vergiler vb.) yöneten Web API controller\'ı.\r\n             Stok bazlı özel vergilendirme kurallarının, oranların ve tarihsel geçerlilik periyotlarının CRUD işlemlerini sağlar.\r\n            \r\n             ENTITY: StokVergi\r\n             ALT_ADLAR: Ürün Vergisi, KDV Oranı, ÖTV Tanımı, Vergi İstisnası, Vergi Muafiyeti, TaxDefinition, StockTaxRate, ItemTax, VAT, SalesTaxConfig\r\n             ROUTE: \/api\/StokVergi\r\n            \r\n             ZORUNLU_ALANLAR:\r\n               StokID    — Verginin tanımlandığı ana stok kartı referansı (zorunlu).\r\n               VergiID   — Uygulanacak vergi türü (KDV %20, ÖTV %45 vb.) referansı.\r\n               BaslangicTarihi — Oranın yasal olarak geçerli olmaya başladığı tarih.\r\n            \r\n             IS_KURALLARI:\r\n               - Aynı stok kartı için aynı vergi türünde (örn: KDV) çakışan tarih aralıklarında (Overlapping) birden fazla aktif tanım bulunamaz.\r\n               - Mevzuat değişikliklerinde (örn: KDV\'nin %18\'den %20\'ye çıkması) eski kayıt silinmemeli, bitiş tarihi verilerek yeni oran için yeni bir satır eklenmelidir.\r\n               - Faturalama motoru, evrak tarihindeki geçerli olan \"StokVergi\" kaydını baz alarak otomatik hesaplama yapar.\r\n            \r\n             ILISKILI_MODULLER:\r\n               - Stok : Verginin atandığı ürün veya hizmet.\r\n               - Fatura \/ Siparis \/ Irsaliye : Otomatik vergi hesaplama ve matrah ayrıştırma süreçleri.\r\n               - Muhasebe : Vergi tutarlarının doğru hesap kodlarına (391\/191 vb.) yansıtılması.\r\n            \r\n             MCP_CATEGORY: StokYonetimi\r\n             MCP_ONCELIK: Bir ürünün vergi oranını sorgulamak veya mevzuat değişikliği sonrası toplu vergi güncellemesi yapmak için kullanılır.\r\n                          Satış dökümanı oluşturulurken uygulanacak güncel oranı çekmek için ListeGet; yeni tanımlar için Post\/Put tercih edilir.\n\n[Endpoint İşlevi]:\nBelirtilen ID\'ye sahip kaydı getirir. Kart detay bilgilerini döndürür.\r\nINTENT: kaydı getir, detayı göster, bilgileri al, ID ile sorgula, kartı görüntüle\r\nKULLANIM: Kart görüntüleme, düzenleme öncesi mevcut bilgileri alma.',
  {
    pathParams: StokVergiGetGetParams
  },
  StokVergi_GetGetHandler
);

server.tool(
  'StokVergi_PutPut',
  '[Kategori\/Controller: StokVergi]\n\nERP stok sistemindeki ürünlere faturalama ve maliyetleme aşamasında uygulanacak otomatik vergi tanımlarını (KDV, ÖTV, Stopaj, Ek Vergiler vb.) yöneten Web API controller\'ı.\r\n             Stok bazlı özel vergilendirme kurallarının, oranların ve tarihsel geçerlilik periyotlarının CRUD işlemlerini sağlar.\r\n            \r\n             ENTITY: StokVergi\r\n             ALT_ADLAR: Ürün Vergisi, KDV Oranı, ÖTV Tanımı, Vergi İstisnası, Vergi Muafiyeti, TaxDefinition, StockTaxRate, ItemTax, VAT, SalesTaxConfig\r\n             ROUTE: \/api\/StokVergi\r\n            \r\n             ZORUNLU_ALANLAR:\r\n               StokID    — Verginin tanımlandığı ana stok kartı referansı (zorunlu).\r\n               VergiID   — Uygulanacak vergi türü (KDV %20, ÖTV %45 vb.) referansı.\r\n               BaslangicTarihi — Oranın yasal olarak geçerli olmaya başladığı tarih.\r\n            \r\n             IS_KURALLARI:\r\n               - Aynı stok kartı için aynı vergi türünde (örn: KDV) çakışan tarih aralıklarında (Overlapping) birden fazla aktif tanım bulunamaz.\r\n               - Mevzuat değişikliklerinde (örn: KDV\'nin %18\'den %20\'ye çıkması) eski kayıt silinmemeli, bitiş tarihi verilerek yeni oran için yeni bir satır eklenmelidir.\r\n               - Faturalama motoru, evrak tarihindeki geçerli olan \"StokVergi\" kaydını baz alarak otomatik hesaplama yapar.\r\n            \r\n             ILISKILI_MODULLER:\r\n               - Stok : Verginin atandığı ürün veya hizmet.\r\n               - Fatura \/ Siparis \/ Irsaliye : Otomatik vergi hesaplama ve matrah ayrıştırma süreçleri.\r\n               - Muhasebe : Vergi tutarlarının doğru hesap kodlarına (391\/191 vb.) yansıtılması.\r\n            \r\n             MCP_CATEGORY: StokYonetimi\r\n             MCP_ONCELIK: Bir ürünün vergi oranını sorgulamak veya mevzuat değişikliği sonrası toplu vergi güncellemesi yapmak için kullanılır.\r\n                          Satış dökümanı oluşturulurken uygulanacak güncel oranı çekmek için ListeGet; yeni tanımlar için Post\/Put tercih edilir.\n\n[Endpoint İşlevi]:\n(endpoint aciklamasi yok)',
  {
    pathParams: StokVergiPutPutParams,
    bodyParams: StokVergiPutPutBody
  },
  StokVergi_PutPutHandler
);

