server.tool(
  'Takvim_DegisiklikGecmisiGet',
  '[Kategori\/Controller: Takvim]\n\nERP sistemindeki çalışma takvimlerinin (Haftalık çalışma günleri, Vardiya düzenleri, Tatil tanımları vb.) başlık yönetimi için Web API controller\'ı.\r\n             İşletmenin operasyonel zaman dilimlerini, vardiya sistemlerini ve resmi\/özel tatil şablonlarını yönetir.\r\n            \r\n             ENTITY: Takvim\r\n             ALT_ADLAR: Çalışma Takvimi, Vardiya Takvimi, Tatil Planı, Operasyonel Takvim, WorkingCalendar, ShiftCalendar, HolidayPlan, TimeTable, ProductionCalendar\r\n             ROUTE: \/api\/Takvim\r\n            \r\n             ZORUNLU_ALANLAR:\r\n               TakvimKodu — Takvimin sistemdeki benzersiz kodu (örn: STANDART-2024).\r\n               TakvimAdi  — Takvimin açıklayıcı ismi (örn: Genel Fabrika Çalışma Takvimi).\r\n            \r\n             IS_KURALLARI:\r\n               - Takvim kodları sistem genelinde benzersiz olmalıdır.\r\n               - Aktif olarak bir Makine, Personel veya Üretim Akışı ile ilişkilendirilmiş takvimler silinemez; bu işlemlerin planlama verilerinin bozulmaması için pasife alınabilir.\r\n               - Takvim başlığı oluşturulduktan sonra, bu takvime bağlı detaylı gün\/saat tanımları (TakvimStr) yapılmalıdır.\r\n            \r\n             ILISKILI_MODULLER:\r\n               - Personel \/ Puantaj : Personelin mesai ve tatil hesaplamaları.\r\n               - Uretim : Makinelerin kapasite planlaması ve iş emri terminleme süreçleri.\r\n               - Gorevler : Görev atamalarında iş günü ve teslim tarihleri hesabı.\r\n               - TakvimStr : Takvime bağlı detaylı tarih ve mesai dökümü.\r\n            \r\n             MCP_CATEGORY: SistemYonetimi\r\n             MCP_ONCELIK: Şirkette tanımlı çalışma düzenlerini listelemek veya yeni bir vardiya planı başlatmak için kullanılır.\r\n                          Takvim listesini çekmek için ListeGet; tanımları güncellemek için Put tercih edilir.\n\n[Endpoint İşlevi]:\nBelirtilen kaydın değişiklik geçmişini getirir. Kim, ne zaman, ne değiştirdi bilgisi.\r\nINTENT: değişiklik geçmişi, kim değiştirdi, ne zaman değişti, log, audit, tarihçe\r\nKULLANIM: Kayıt üzerinde yapılan tüm değişikliklerin izlenmesi ve denetimi.',
  {
    pathParams: TakvimDegisiklikGecmisiGetParams,
    queryParams: TakvimDegisiklikGecmisiGetQueryParams
  },
  Takvim_DegisiklikGecmisiGetHandler
);

server.tool(
  'Takvim_BelgelerGet',
  '[Kategori\/Controller: Takvim]\n\nERP sistemindeki çalışma takvimlerinin (Haftalık çalışma günleri, Vardiya düzenleri, Tatil tanımları vb.) başlık yönetimi için Web API controller\'ı.\r\n             İşletmenin operasyonel zaman dilimlerini, vardiya sistemlerini ve resmi\/özel tatil şablonlarını yönetir.\r\n            \r\n             ENTITY: Takvim\r\n             ALT_ADLAR: Çalışma Takvimi, Vardiya Takvimi, Tatil Planı, Operasyonel Takvim, WorkingCalendar, ShiftCalendar, HolidayPlan, TimeTable, ProductionCalendar\r\n             ROUTE: \/api\/Takvim\r\n            \r\n             ZORUNLU_ALANLAR:\r\n               TakvimKodu — Takvimin sistemdeki benzersiz kodu (örn: STANDART-2024).\r\n               TakvimAdi  — Takvimin açıklayıcı ismi (örn: Genel Fabrika Çalışma Takvimi).\r\n            \r\n             IS_KURALLARI:\r\n               - Takvim kodları sistem genelinde benzersiz olmalıdır.\r\n               - Aktif olarak bir Makine, Personel veya Üretim Akışı ile ilişkilendirilmiş takvimler silinemez; bu işlemlerin planlama verilerinin bozulmaması için pasife alınabilir.\r\n               - Takvim başlığı oluşturulduktan sonra, bu takvime bağlı detaylı gün\/saat tanımları (TakvimStr) yapılmalıdır.\r\n            \r\n             ILISKILI_MODULLER:\r\n               - Personel \/ Puantaj : Personelin mesai ve tatil hesaplamaları.\r\n               - Uretim : Makinelerin kapasite planlaması ve iş emri terminleme süreçleri.\r\n               - Gorevler : Görev atamalarında iş günü ve teslim tarihleri hesabı.\r\n               - TakvimStr : Takvime bağlı detaylı tarih ve mesai dökümü.\r\n            \r\n             MCP_CATEGORY: SistemYonetimi\r\n             MCP_ONCELIK: Şirkette tanımlı çalışma düzenlerini listelemek veya yeni bir vardiya planı başlatmak için kullanılır.\r\n                          Takvim listesini çekmek için ListeGet; tanımları güncellemek için Put tercih edilir.\n\n[Endpoint İşlevi]:\nBelirtilen kayda ait belge listesini getirir.\r\nINTENT: belgeleri getir, dosyaları listele, ekleri göster, dokümanlar\r\nKULLANIM: Kayda eklenmiş sözleşme, fatura, resim gibi belgelerin listelenmesi.',
  {
    pathParams: TakvimBelgelerGetParams,
    queryParams: TakvimBelgelerGetQueryParams
  },
  Takvim_BelgelerGetHandler
);

