server.tool(
  'UrOperasyonMakine_GetGet',
  '[Kategori\/Controller: UrOperasyonMakine]\n\nERP üretim sistemindeki Operasyonların hangi Makinelerde\/İş Merkezlerinde yapılabileceğini tanımlayan (Operasyon-Makine Yetkinlik Matrisi) Web API controller\'ı.\r\n             Belirli bir prosesin hangi ekipmanlarla gerçekleştirilebileceğini, makine bazlı spesifik hazırlık (Setup) ve işlem sürelerini yöneten CRUD işlemlerini sağlar.\r\n            \r\n             ENTITY: UrOperasyonMakine\r\n             ALT_ADLAR: Operasyon-Makine Eşleşmesi, Makine Yetkinliği, Ekipman Kapasite Matrisi, Rota-Makine İlişkisi, Operation-Machine Mapping, Equipment Competency, Work Center Capability, Resource Calibration\r\n             ROUTE: \/api\/UrOperasyonMakine\r\n            \r\n             ZORUNLU_ALANLAR:\r\n               OperasyonID — Tanımlanan teknik prosesin referansı (zorunlu).\r\n               MakineID    — Operasyonu gerçekleştirecek fiziksel ekipman referansı (zorunlu).\r\n            \r\n             IS_KURALLARI:\r\n               - Aynı Operasyon ve Makine ikilisi için sistemde sadece bir aktif eşleşme tanımı bulunabilir.\r\n               - Makineye özel süreler (Hazırlık, İşlem vb.); genel operasyon sürelerinden farklıysa (örn: yeni makine daha hızlıysa) burada override edilir.\r\n               - Üretim Çizelgeleme (APS) motoru, bir iş emrini planlarken bu tabloyu kontrol ederek operasyonu yapabilecek \"Alternatif Makine\" opsiyonlarını değerlendirir.\r\n               - Aktif bir Üretim Rotasında (Routing) ana kaynak veya alternatif kaynak olarak tanımlı olan eşleşmeler silinemez.\r\n            \r\n             ILISKILI_MODULLER:\r\n               - UrOperasyon : Tanımlanan genel iş adımı.\r\n               - UrMakine : Operasyonu yapacak fiziksel kaynak.\r\n               - UrReceteOperasyon : Ürün bazlı rotalarda hangi makinenin öncelikli (Primary) kullanılacağı.\r\n               - Uretim : Fiili üretim sonu onaylarında (Backflush) seçilen makineye göre süre hesaplamaları.\r\n            \r\n             MCP_CATEGORY: UretimYonetimi\r\n             MCP_ONCELIK: Bir operasyonun hangi makinelerde yapılabileceğini sorgulamak (Darboğaz analizi) veya makine yetkinlik matrisini listelemek için ListeGet kullanılır.\r\n                          Parkura yeni yetenekler eklemek (örn: bu makine artık bu işi de yapabiliyor) için Post tercih edilir.\n\n[Endpoint İşlevi]:\nBelirtilen ID\'ye sahip kaydı getirir. Kart detay bilgilerini döndürür.\r\nINTENT: kaydı getir, detayı göster, bilgileri al, ID ile sorgula, kartı görüntüle\r\nKULLANIM: Kart görüntüleme, düzenleme öncesi mevcut bilgileri alma.',
  {
    pathParams: UrOperasyonMakineGetGetParams
  },
  UrOperasyonMakine_GetGetHandler
);

server.tool(
  'UrOperasyonMakine_PutPut',
  '[Kategori\/Controller: UrOperasyonMakine]\n\nERP üretim sistemindeki Operasyonların hangi Makinelerde\/İş Merkezlerinde yapılabileceğini tanımlayan (Operasyon-Makine Yetkinlik Matrisi) Web API controller\'ı.\r\n             Belirli bir prosesin hangi ekipmanlarla gerçekleştirilebileceğini, makine bazlı spesifik hazırlık (Setup) ve işlem sürelerini yöneten CRUD işlemlerini sağlar.\r\n            \r\n             ENTITY: UrOperasyonMakine\r\n             ALT_ADLAR: Operasyon-Makine Eşleşmesi, Makine Yetkinliği, Ekipman Kapasite Matrisi, Rota-Makine İlişkisi, Operation-Machine Mapping, Equipment Competency, Work Center Capability, Resource Calibration\r\n             ROUTE: \/api\/UrOperasyonMakine\r\n            \r\n             ZORUNLU_ALANLAR:\r\n               OperasyonID — Tanımlanan teknik prosesin referansı (zorunlu).\r\n               MakineID    — Operasyonu gerçekleştirecek fiziksel ekipman referansı (zorunlu).\r\n            \r\n             IS_KURALLARI:\r\n               - Aynı Operasyon ve Makine ikilisi için sistemde sadece bir aktif eşleşme tanımı bulunabilir.\r\n               - Makineye özel süreler (Hazırlık, İşlem vb.); genel operasyon sürelerinden farklıysa (örn: yeni makine daha hızlıysa) burada override edilir.\r\n               - Üretim Çizelgeleme (APS) motoru, bir iş emrini planlarken bu tabloyu kontrol ederek operasyonu yapabilecek \"Alternatif Makine\" opsiyonlarını değerlendirir.\r\n               - Aktif bir Üretim Rotasında (Routing) ana kaynak veya alternatif kaynak olarak tanımlı olan eşleşmeler silinemez.\r\n            \r\n             ILISKILI_MODULLER:\r\n               - UrOperasyon : Tanımlanan genel iş adımı.\r\n               - UrMakine : Operasyonu yapacak fiziksel kaynak.\r\n               - UrReceteOperasyon : Ürün bazlı rotalarda hangi makinenin öncelikli (Primary) kullanılacağı.\r\n               - Uretim : Fiili üretim sonu onaylarında (Backflush) seçilen makineye göre süre hesaplamaları.\r\n            \r\n             MCP_CATEGORY: UretimYonetimi\r\n             MCP_ONCELIK: Bir operasyonun hangi makinelerde yapılabileceğini sorgulamak (Darboğaz analizi) veya makine yetkinlik matrisini listelemek için ListeGet kullanılır.\r\n                          Parkura yeni yetenekler eklemek (örn: bu makine artık bu işi de yapabiliyor) için Post tercih edilir.\n\n[Endpoint İşlevi]:\n(endpoint aciklamasi yok)',
  {
    pathParams: UrOperasyonMakinePutPutParams,
    bodyParams: UrOperasyonMakinePutPutBody
  },
  UrOperasyonMakine_PutPutHandler
);

