server.tool(
  'UrRecete_ReceteDetaylariGetirGet',
  '[Kategori\/Controller: UrRecete]\n\nERP üretim sistemindeki Ürün Ağaçlarının (BOM - Bill of Materials) ve üretim reçetelerinin yönetimi için Web API controller\'ı.\r\n             Üretim süreçlerinde kullanılan hammaddelerin, operasyon adımlarının ve yarı mamul hiyerarşilerinin CRUD işlemlerini, maliyet simülasyonlarını ve ağaç yapısı sorgulamalarını sağlar.\r\n            \r\n             ENTITY: UrRecete\r\n             ALT_ADLAR: Ürün Ağacı, Reçete Tanımı, İmalat Formülü, Malzeme Listesi, BOM, Bill of Materials, Recipe, Assembly Tree, Component List, Production Formula\r\n             ROUTE: \/api\/UrRecete\r\n            \r\n             ZORUNLU_ALANLAR:\r\n               ReceteKodu — Reçetenin sistemdeki benzersiz kodu (örn: R01-MAMUL-A).\r\n               MamulStokID — Reçetenin ait olduğu ana ürün (Mamul\/Yarı Mamul) referansı.\r\n            \r\n             IS_KURALARI:\r\n               - Reçete kodları sistem genelinde benzersiz olmalıdır.\r\n               - Bir mamulün birden fazla alternatf reçetesi (örn: Seri Üretim Reçetesi, Numune Reçetesi vb.) olabilir.\r\n               - Aktif bir İş Emri (Work Order) tarafından kullanılan veya \"Onaylı\/Kesinleşmiş\" durumdaki reçeteler üzerinde kritik değişiklikler yapılamaz; revizyon yönetimi önerilir.\r\n               - Reçete hiyerarşisinde döngüsel referans (Self-referencing loop) kontrolü sistem tarafından yapılır.\r\n            \r\n             ILISKILI_MODULLER:\r\n               - Stok : Reçeteye konu olan mamul ve reçete içindeki hammaddeler.\r\n               - UrReceteOperasyon : Reçeteye bağlı iş adımları ve rotalar.\r\n               - Uretim : İş emirlerinin malzeme ve operasyon gereksinimlerinin planlanması (MRP).\r\n               - Satinalma : Reçete bazlı hammadde eksikliklerinin (İhtiyaç Planlama) tespiti.\r\n            \r\n             MCP_CATEGORY: UretimYonetimi\r\n             MCP_ONCELIK: Üretilecek bir ürünün içeriğini (Hammadde\/Operasyon) sorgulamak veya maliyet analizi yapmak için ListeGet kullanılır.\r\n                          Yeni bir ürün tasarımı yapıldığında Post; teknik değişikliklerde Put tercih edilir.\r\n                          Ağaç yapısını tüm kırılımlarıyla görmek için OperasyonMamulHammaddeIleAltReceteIleDetayli ucu kullanılır.\n\n[Endpoint İşlevi]:\nReçeteye bağlı tüm kalemlerin (hammadde, operasyon vb.) düz bir liste halinde Excel uyumlu dökümünü getirir.',
  {
    queryParams: UrReceteReceteDetaylariGetirGetQueryParams
  },
  UrRecete_ReceteDetaylariGetirGetHandler
);

server.tool(
  'UrRecete_OperasyonMamulHammaddeIleAltReceteIleDetayliGet',
  '[Kategori\/Controller: UrRecete]\n\nERP üretim sistemindeki Ürün Ağaçlarının (BOM - Bill of Materials) ve üretim reçetelerinin yönetimi için Web API controller\'ı.\r\n             Üretim süreçlerinde kullanılan hammaddelerin, operasyon adımlarının ve yarı mamul hiyerarşilerinin CRUD işlemlerini, maliyet simülasyonlarını ve ağaç yapısı sorgulamalarını sağlar.\r\n            \r\n             ENTITY: UrRecete\r\n             ALT_ADLAR: Ürün Ağacı, Reçete Tanımı, İmalat Formülü, Malzeme Listesi, BOM, Bill of Materials, Recipe, Assembly Tree, Component List, Production Formula\r\n             ROUTE: \/api\/UrRecete\r\n            \r\n             ZORUNLU_ALANLAR:\r\n               ReceteKodu — Reçetenin sistemdeki benzersiz kodu (örn: R01-MAMUL-A).\r\n               MamulStokID — Reçetenin ait olduğu ana ürün (Mamul\/Yarı Mamul) referansı.\r\n            \r\n             IS_KURALARI:\r\n               - Reçete kodları sistem genelinde benzersiz olmalıdır.\r\n               - Bir mamulün birden fazla alternatf reçetesi (örn: Seri Üretim Reçetesi, Numune Reçetesi vb.) olabilir.\r\n               - Aktif bir İş Emri (Work Order) tarafından kullanılan veya \"Onaylı\/Kesinleşmiş\" durumdaki reçeteler üzerinde kritik değişiklikler yapılamaz; revizyon yönetimi önerilir.\r\n               - Reçete hiyerarşisinde döngüsel referans (Self-referencing loop) kontrolü sistem tarafından yapılır.\r\n            \r\n             ILISKILI_MODULLER:\r\n               - Stok : Reçeteye konu olan mamul ve reçete içindeki hammaddeler.\r\n               - UrReceteOperasyon : Reçeteye bağlı iş adımları ve rotalar.\r\n               - Uretim : İş emirlerinin malzeme ve operasyon gereksinimlerinin planlanması (MRP).\r\n               - Satinalma : Reçete bazlı hammadde eksikliklerinin (İhtiyaç Planlama) tespiti.\r\n            \r\n             MCP_CATEGORY: UretimYonetimi\r\n             MCP_ONCELIK: Üretilecek bir ürünün içeriğini (Hammadde\/Operasyon) sorgulamak veya maliyet analizi yapmak için ListeGet kullanılır.\r\n                          Yeni bir ürün tasarımı yapıldığında Post; teknik değişikliklerde Put tercih edilir.\r\n                          Ağaç yapısını tüm kırılımlarıyla görmek için OperasyonMamulHammaddeIleAltReceteIleDetayli ucu kullanılır.\n\n[Endpoint İşlevi]:\nReçeteyi hiyerarşik (ağaç yapısı) şeklinde; operasyonlar, malzemeler ve alt reçetelerle birlikte getirir.',
  {
    queryParams: UrReceteOperasyonMamulHammaddeIleAltReceteIleDetayliGetQueryParams
  },
  UrRecete_OperasyonMamulHammaddeIleAltReceteIleDetayliGetHandler
);

