server.tool(
  'VergiDairesi_GetGet',
  '[Kategori\/Controller: VergiDairesi]\n\nERP sistemindeki resmi Vergi Dairesi tanımlarının yönetimi için Web API controller\'ı.\r\n             Cari kartlarında (Müşteri\/Tedarikçi), şirket parametrelerinde ve yasal beyannamelerde (e-Fatura, e-Arşiv vb.) kullanılan vergi dairesi bilgilerinin CRUD işlemlerini sağlar.\r\n            \r\n             ENTITY: VergiDairesi\r\n             ALT_ADLAR: Vergi Dairesi, Vergi Ofisi, Maliye Birimi, Tax Office, Revenue Office, Tax Administration, IRS Office, Tax Authority\r\n             ROUTE: \/api\/VergiDairesi\r\n            \r\n             ZORUNLU_ALANLAR:\r\n               VergiDairesiKodu — Gelir İdaresi Başkanlığı (GİB) tarafından belirlenen resmi kod (zorunlu).\r\n               VergiDairesiAdi  — Vergi dairesinin resmi adı (zorunlu).\r\n            \r\n             IS_KURALARI:\r\n               - Vergi dairesi kodları ülke ve şehir bazında yasal standartlara uygun ve benzersiz olmalıdır.\r\n               - Herhangi bir Cari Kartına, Şirket Tanımına veya Personel Özlük Bilgisine bağlanmış olan vergi daireleri veri bütünlüğü gereği silinemez.\r\n               - e-Fatura ve e-Arşiv süreçlerinde gönderici ve alıcı vergi dairesi bilgilerinin doğruluğu GİB kontrolleri için kritiktir.\r\n            \r\n             ILISKILI_MODULLER:\r\n               - Cari : Müşteri ve tedarikçilerin yasal adres ve vergi bilgileri.\r\n               - Sirketler : İşletmenin bağlı olduğu ana vergi dairesi.\r\n               - Fatura : e-Fatura\/e-Arşiv XML şemalarında yer alan yasal zorunluluklar.\r\n               - Iller \/ Ilceler : Vergi dairesinin bulunduğu coğrafi lokasyonun tespiti.\r\n            \r\n             MCP_CATEGORY: SistemYonetimi\r\n             MCP_ONCELIK: Cari kartı açılırken veya şirket yasal bilgileri düzenlenirken vergi dairesi seçim listesini (lookup) doldurmak için ListeGet kullanılır.\r\n                          Yeni bir yasal birim eklendiğinde Post; isim\/kod revizeleri için Put tercih edilir.\n\n[Endpoint İşlevi]:\nBelirtilen ID\'ye sahip kaydı getirir. Kart detay bilgilerini döndürür.\r\nINTENT: kaydı getir, detayı göster, bilgileri al, ID ile sorgula, kartı görüntüle\r\nKULLANIM: Kart görüntüleme, düzenleme öncesi mevcut bilgileri alma.',
  {
    pathParams: VergiDairesiGetGetParams
  },
  VergiDairesi_GetGetHandler
);

server.tool(
  'VergiDairesi_PutPut',
  '[Kategori\/Controller: VergiDairesi]\n\nERP sistemindeki resmi Vergi Dairesi tanımlarının yönetimi için Web API controller\'ı.\r\n             Cari kartlarında (Müşteri\/Tedarikçi), şirket parametrelerinde ve yasal beyannamelerde (e-Fatura, e-Arşiv vb.) kullanılan vergi dairesi bilgilerinin CRUD işlemlerini sağlar.\r\n            \r\n             ENTITY: VergiDairesi\r\n             ALT_ADLAR: Vergi Dairesi, Vergi Ofisi, Maliye Birimi, Tax Office, Revenue Office, Tax Administration, IRS Office, Tax Authority\r\n             ROUTE: \/api\/VergiDairesi\r\n            \r\n             ZORUNLU_ALANLAR:\r\n               VergiDairesiKodu — Gelir İdaresi Başkanlığı (GİB) tarafından belirlenen resmi kod (zorunlu).\r\n               VergiDairesiAdi  — Vergi dairesinin resmi adı (zorunlu).\r\n            \r\n             IS_KURALARI:\r\n               - Vergi dairesi kodları ülke ve şehir bazında yasal standartlara uygun ve benzersiz olmalıdır.\r\n               - Herhangi bir Cari Kartına, Şirket Tanımına veya Personel Özlük Bilgisine bağlanmış olan vergi daireleri veri bütünlüğü gereği silinemez.\r\n               - e-Fatura ve e-Arşiv süreçlerinde gönderici ve alıcı vergi dairesi bilgilerinin doğruluğu GİB kontrolleri için kritiktir.\r\n            \r\n             ILISKILI_MODULLER:\r\n               - Cari : Müşteri ve tedarikçilerin yasal adres ve vergi bilgileri.\r\n               - Sirketler : İşletmenin bağlı olduğu ana vergi dairesi.\r\n               - Fatura : e-Fatura\/e-Arşiv XML şemalarında yer alan yasal zorunluluklar.\r\n               - Iller \/ Ilceler : Vergi dairesinin bulunduğu coğrafi lokasyonun tespiti.\r\n            \r\n             MCP_CATEGORY: SistemYonetimi\r\n             MCP_ONCELIK: Cari kartı açılırken veya şirket yasal bilgileri düzenlenirken vergi dairesi seçim listesini (lookup) doldurmak için ListeGet kullanılır.\r\n                          Yeni bir yasal birim eklendiğinde Post; isim\/kod revizeleri için Put tercih edilir.\n\n[Endpoint İşlevi]:\n(endpoint aciklamasi yok)',
  {
    pathParams: VergiDairesiPutPutParams,
    bodyParams: VergiDairesiPutPutBody
  },
  VergiDairesi_PutPutHandler
);

